    def _verify_and_return_sync_response(self, raw_string, response_type):
        response = json.loads(raw_string)
        result = response[response_type]
        sign = response["sign"]
        # locate string to be signed
        raw_string = self._get_string_to_be_signed(raw_string, response_type)
        if not self._verify(raw_string, sign):
            logging.error("_verify_and_return_sync_response")
        return result

    def _get_string_to_be_signed(self, raw_string, response_type):
        """
        https://doc.open.alipay.com/docs/doc.htm?docType=1&articleId=106120
        从同步返回的接口里面找到待签名的字符串
        """
        left_index = 0
        right_index = 0

        index = raw_string.find(response_type)
        left_index = raw_string.find("{", index)
        index = left_index + 1

        balance = -1
        while balance < 0 and index < len(raw_string) - 1:
            index_a = raw_string.find("{", index)
            index_b = raw_string.find("}", index)
            # 右括号没找到， 退出
            if index_b == -1:
                break
            right_index = index_b
            # 左括号没找到，移动到右括号的位置
            if index_a == -1:
                index = index_b + 1
                balance += 1
            # 左括号出现在有括号之前，移动到左括号的位置
            elif index_a > index_b:
                balance += 1
                index = index_b + 1
            # 左括号出现在右括号之后， 移动到右括号的位置
            else:
                balance -= 1
                index = index_a + 1

        return raw_string[left_index: right_index + 1]



class ISVAliPay(BaseAliPay):

    def __init__(self,appid,app_notify_url,sign_type="RSA2", debug=False):
        if not app_auth_token and not app_auth_code:
            raise Exception("Both app_auth_code and app_auth_token are None !!!")
        super(ISVAliPay, self).__init__(appid, app_notify_url,sign_type, debug)

    def set_app_auth_token(self,app_auth_token):
        self._app_auth_token = app_auth_token

    def set_app_auth_code(self,app_auth_code):
        self._app_auth_code = app_auth_code

    def get_app_auth_token(self):
        # 没有则换取token
        if not self._app_auth_token:
            result = self.api_alipay_open_auth_token_app(self._app_auth_code)
            self._app_auth_token = result.get("app_auth_token", None)
        if not self._app_auth_token:
            raise Exception("Get auth token by auth code failed: {}".format(self._app_auth_code))
        return self._app_auth_token

    def build_body(self, method, biz_content, return_url=None, notify_url=None, append_auth_token=True):
        return super(ISVAliPay, self).build_body(method, biz_content, return_url, notify_url, append_auth_token)

    def api_alipay_open_auth_token_app(self, refresh_token=None):
        """
        response = {
          "code": "10000",
          "msg": "Success",
          "app_auth_token": "201708BB28623ce3d10f4f62875e9ef5cbeebX07",
          "app_refresh_token": "201708BB108a270d8bb6409890d16175a04a7X07",
          "auth_app_id": "appid",
          "expires_in": 31536000,
          "re_expires_in": 32140800,
          "user_id": "2088xxxxx
        }
        """
        if refresh_token:
            biz_content = {"grant_type": "refresh_token","refresh_token": refresh_token}
        else:
            biz_content = {"grant_type": "authorization_code","code": self._app_auth_code}
        data = self.build_body("alipay.open.auth.token.app",biz_content,append_auth_token=False)
        url = self.gateway + "?" + self.sign_data(data)
        raw_string = urlopen(url, timeout=15).read().decode("utf-8")
        return self._verify_and_return_sync_response(raw_string, "alipay_open_auth_token_app_response")

    def api_alipay_open_auth_token_app_query(self):
        biz_content = {"app_auth_token": self.get_app_auth_token()}
        data = self.build_body("alipay.open.auth.token.app.query",biz_content,append_auth_token=False)
        url = self.gateway + "?" + self.sign_data(data)
        raw_string = urlopen(url, timeout=15).read().decode("utf-8")
        return self._verify_and_return_sync_response(raw_string, "alipay_open_auth_token_app_query_response")


