class Handler(BaseHandler):
    crawl_config = {
    }

    def on_start(self):        
        for part in xrange(3200):
            self.crawl("data:,part-%d" % part, callback=self.part, save=part)

    def part(self, response):
        
        for url_two in xrange(1000):
            
            url_one = 'http://wd.####.com/wd/shop/getPubInfo?param={%22userID%22:%22'
            url_three = '%22}'
            
            url_two = response.save * 1000 + url_two
            
            N_Url = url_one+str(url_two)+url_three
            
            self.crawl(N_Url, callback=self.json_parser)
    
    @config(priority=2)
    def json_parser(self,response):
        
        if len(response.json) == 2:
            
            uid = response.json['result']['id']
            country_code = response.json['result']['country_code']
            if response.json['result']['shopName'] is None:
                shopName = u'空'
            else:
                shopName = response.json['result']['shopName']
            shopURL = response.json['result']['shopURL']
            if response.json['result']['weixin'] is None:
                weixin = u'空'
            else:
                weixin = response.json['result']['weixin']
            if response.json['result']['alipay'] is None:
                alipay = u'空'
            else:
                alipay = response.json['result']['alipay']
            add_time = str(response.json['result']['add_time'])
            addtime = int(time.time())
            
            return {
                "uid":uid,
                "country_code":country_code,
                "shopName":shopName,
                "shopURL":shopURL,
                "weixin":weixin,
                "alipay":alipay,
                "add_time":add_time,
                "addtime":addtime
                }
            
    def on_result(self, result):
        #print result
        if not result or not result['uid']:
            return
        sql = SQL()
        sql.replace('weidian',**result)
